section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/python",
  "type": "object",
  "required": ["pythonVersion", "linterFormatter", "typeChecker", "depManager", "servicesLayer"],
  "properties": {
    "pythonVersion": {"type": "string", "pattern": "^\\^?3\\.(1[1-9]|[2-9][0-9])"},
    "linterFormatter": {"const": "ruff"},
    "typeChecker": {
      "type": "object",
      "required": ["tool", "strict"],
      "properties": {
        "tool": {"const": "mypy"},
        "strict": {"const": true}
      }
    },
    "depManager": {"const": "poetry"},
    "servicesLayer": {"type": "boolean", "const": true},
    "forbidden": {
      "type": "array",
      "items": {"enum": [
        "from typing import Optional",
        "from typing import List, Dict",
        "Optional[X]",
        "black + isort + flake8 with ruff"
      ]}
    }
  }
}
